/** Patterns that indicate infrastructure/services rather than packages */
const NON_PACKAGE_PATTERNS = [
  /\s+\/\s+/,        // "Keycloak / Azure Entra ID" — space-slash-space = multi-tool mention (not @scope/pkg)
  /\s(api|sdk|cli|ui|platform|service|server|cloud|saas|layer)$/i,
  /^(self[- ]hosted|managed|hosted)/i,
];

