import { existsSync, readFileSync } from "node:fs";
import { resolve, join } from "node:path";
import { globSync } from "glob";
import type { Claim, DriftIssue } from "../../types.js";

const PLACEHOLDER_WORDS = /(?:^|[/_-])(?:new|example|your|sample|my|foo|bar|placeholder|template)(?:[/_.-]|$)/i;

/**
 * Scoped npm package pattern: `@scope/package` or `@scope/package/...`
 * These are NOT file paths and should be skipped entirely.
 */
const SCOPED_NPM_RE = /^@[a-z0-9][\w.-]*\/[a-z0-9][\w.-]*(?:\/|$)/i;

// ── tsconfig path alias cache ──
interface TsPathMapping {
  prefix: string; // e.g. "@/" or "@components/"
  targets: string[]; // e.g. ["src/"] or ["src/components/"]
}

const tsConfigCache = new Map<string, TsPathMapping[] | null>();

function loadTsPaths(projectRoot: string): TsPathMapping[] | null {
  if (tsConfigCache.has(projectRoot)) return tsConfigCache.get(projectRoot)!;

  const tsconfigPath = join(projectRoot, "tsconfig.json");
  if (!existsSync(tsconfigPath)) {
    tsConfigCache.set(projectRoot, null);
    return null;
  }

  try {
    // Strip single-line comments and trailing commas for lenient JSON parsing
    const raw = readFileSync(tsconfigPath, "utf-8")
      .replace(/\/\/.*$/gm, "")
      .replace(/,\s*([\]}])/g, "$1");
    const tsconfig = JSON.parse(raw);
    const paths: Record<string, string[]> | undefined =
      tsconfig?.compilerOptions?.paths;

    if (!paths || Object.keys(paths).length === 0) {
      tsConfigCache.set(projectRoot, null);
      return null;
    }

    const mappings: TsPathMapping[] = [];
    for (const [pattern, targets] of Object.entries(paths)) {
      // Pattern like "@/*" → prefix "@/", targets like ["src/*"] → "src/"
      const prefix = pattern.replace(/\*$/, "");
      const resolved = targets.map((t) => t.replace(/\*$/, ""));
      mappings.push({ prefix, targets: resolved });
    }

    tsConfigCache.set(projectRoot, mappings);
    return mappings;
  } catch {
    tsConfigCache.set(projectRoot, null);
    return null;
  }
}

/**
 * Try resolving a path alias (`@/foo`, `@components/foo`, `~/foo`) to a real
 * disk path. Returns true if any resolved candidate exists.
 */
function resolveAlias(
  value: string,
  projectRoot: string,
): boolean {
  // ── tsconfig.json paths ──
  const mappings = loadTsPaths(projectRoot);
  if (mappings) {
    for (const { prefix, targets } of mappings) {
      if (value.startsWith(prefix)) {
        const rest = value.slice(prefix.length);
        for (const target of targets) {
          if (existsSync(resolve(projectRoot, target + rest))) return true;
        }
      }
    }
  }

  // ── ~ alias (Nuxt/Vite convention: ~ → project root) ──
  if (value.startsWith("~/")) {
    const stripped = value.slice(2);
    if (existsSync(resolve(projectRoot, stripped))) return true;
    // Common convention: ~/components → src/components
    if (existsSync(resolve(projectRoot, "src", stripped))) return true;
  }

  return false;
}

/** Check that all claimed paths exist on disk */
export function checkPaths(
  claims: Claim[],
  projectRoot: string,
  scaffoldRoot: string
): DriftIssue[] {
  const issues: DriftIssue[] = [];
  const pathClaims = claims.filter(
    (c) => c.kind === "path" && !c.negated
  );

  for (const claim of pathClaims) {
    // Skip scoped npm packages — they are dependencies, not file paths
    if (SCOPED_NPM_RE.test(claim.value)) continue;

    if (pathExists(claim.value, projectRoot, scaffoldRoot)) continue;

    // Downgrade to warning when confidence is low:
    // - pattern files, placeholder words, example-intent claims
    // - bare filenames without slashes (often named as supported formats, not repo-specific claims)
    // - medium-confidence claims (less certain the file should exist here)
    const isPattern = claim.source.includes("patterns/");
    const isPlaceholder = PLACEHOLDER_WORDS.test(claim.value);
    const isExample = claim.intent === "example" || claim.confidence === "low";
    const isBareFilename = !claim.value.includes("/");
    const isMediumConfidence = claim.confidence === "medium";
    const severity = isPattern || isPlaceholder || isExample || isBareFilename || isMediumConfidence ? "warning" : "error";

    issues.push({
      code: "MISSING_PATH",
      severity,
      file: claim.source,
      line: claim.line,
      message: `Referenced path does not exist: ${claim.value}`,
      claim,
      suggestion: isExample
        ? `Replace the illustrative path \`${claim.value}\` with a real repo path or mark it more explicitly as an example.`
        : `Update this scaffold reference to an existing path, or create the missing file at \`${claim.value}\` if it should exist.`,
    });
  }

  return issues;
}

const pathExistsCache = new Map<string, boolean>();

/** Lazy-built index of all filenames → relative paths in the project.
 *  Built once per project on first fuzzy lookup; avoids repeated recursive globs. */
let fileIndexProject: string | null = null;
let fileIndex: Map<string, string[]> | null = null;

function getFileIndex(projectRoot: string): Map<string, string[]> {
  if (fileIndex && fileIndexProject === projectRoot) return fileIndex;
  fileIndex = new Map();
  fileIndexProject = projectRoot;
  const allFiles = globSync("**/*", {
    cwd: projectRoot,
    ignore: ["node_modules/**", ".cai/**", ".context-condensing/**", "dist/**", ".git/**", "build/**"],
    maxDepth: 6,
    nodir: true,
  });
  for (const f of allFiles) {
    const name = f.split("/").pop()!;
    if (!fileIndex.has(name)) fileIndex.set(name, []);
    fileIndex.get(name)!.push(f);
  }
  return fileIndex;
}

function pathExists(value: string, projectRoot: string, scaffoldRoot: string): boolean {
  const cacheKey = `${projectRoot}:${value}`;
  const cached = pathExistsCache.get(cacheKey);
  if (cached !== undefined) return cached;
  const result = pathExistsUncached(value, projectRoot, scaffoldRoot);
  pathExistsCache.set(cacheKey, result);
  return result;
}

function pathExistsUncached(value: string, projectRoot: string, scaffoldRoot: string): boolean {
  // Try project root first (e.g. src/index.ts)
  if (existsSync(resolve(projectRoot, value))) return true;

  // Try scaffold root (e.g. context/architecture.md when scaffold is in a dedicated hidden directory)
  if (scaffoldRoot !== projectRoot) {
    if (existsSync(resolve(scaffoldRoot, value))) return true;
  }

  // If path starts with a scaffold directory prefix, also check without that prefix.
  // This handles local repo layouts where the scaffold files live at the repo root.
  for (const prefix of [".cai/", ".context-condensing/"]) {
    if (value.startsWith(prefix)) {
      const withoutPrefix = value.slice(prefix.length);
      if (existsSync(resolve(projectRoot, withoutPrefix))) return true;
    }
  }

  // Try resolving TypeScript/bundler path aliases (@/, @components/, ~/)
  if (value.startsWith("@") || value.startsWith("~/")) {
    if (resolveAlias(value, projectRoot)) return true;
  }

  // Fuzzy search via pre-built file index (one glob for all lookups instead of one per path).
  // e.g. "drift/index.ts" exists at "src/drift/index.ts"
  const fileName = value.split("/").pop();
  if (fileName) {
    const idx = getFileIndex(projectRoot);
    const candidates = idx.get(fileName);
    if (candidates?.some((c) => c === value || c.endsWith("/" + value))) return true;
  }

  return false;
}

/** Exported for testing: clear the tsconfig cache between test runs */
export function _clearTsConfigCache(): void {
  tsConfigCache.clear();
}
