import { relative } from "node:path";
import type {
  CheckerSummary,
  DriftCheckerName,
  DriftContext,
  DriftIssue,
} from "../types.js";
import { parseFrontmatter } from "./frontmatter.js";
import { checkCommands } from "./checkers/command.js";
import { checkCrossFile } from "./checkers/cross-file.js";
import { checkDependencies } from "./checkers/dependency.js";
import { checkEdges } from "./checkers/edges.js";
import { checkIndexSync } from "./checkers/index-sync.js";
import { checkPaths } from "./checkers/path.js";
import { checkScriptCoverage } from "./checkers/script-coverage.js";
import { checkStalenessBatch } from "./checkers/staleness.js";
import { checkToolConfigs, getExistingToolConfigs } from "./checkers/tool-configs.js";
import { checkWorkspaceDependencies } from "./checkers/workspace-dependencies.js";

export interface DriftChecker {
  name: DriftCheckerName;
  run(context: DriftContext): Promise<CheckerRunResult> | CheckerRunResult;
}

export interface CheckerRunResult {
  issues: DriftIssue[];
  checked: number;
}

export const AVAILABLE_DRIFT_CHECKERS: DriftCheckerName[] = [
  "edges",
  "staleness",
  "path",
  "command",
  "dependency",
  "cross-file",
  "workspace-dependencies",
  "index-sync",
  "tool-configs",
  "script-coverage",
];

export function createDriftRegistry(): DriftChecker[] {
  return [
    {
      name: "edges",
      run(context) {
        let checked = 0;
        const issues: DriftIssue[] = [];
        for (const filePath of context.scaffoldFiles) {
          const source = relative(context.projectRoot, filePath);
          const frontmatter = parseFrontmatter(filePath);
          issues.push(
            ...checkEdges(
              frontmatter,
              filePath,
              source,
              context.projectRoot,
              context.scaffoldRoot
            )
          );
          checked++;
        }
        return { issues, checked };
      },
    },
    {
      name: "staleness",
      async run(context) {
        const sources = context.scaffoldFiles.map((f) => relative(context.projectRoot, f));
        const issues = await checkStalenessBatch(
          sources,
          context.projectRoot,
          context.staleness
        );
        return { issues, checked: sources.length };
      },
    },
    {
      name: "path",
      run(context) {
        const checked = context.claims.filter((claim) => claim.kind === "path" && !claim.negated).length;
        return {
          issues: checkPaths(context.claims, context.projectRoot, context.scaffoldRoot),
          checked,
        };
      },
    },
    {
      name: "command",
      run(context) {
        const checked = context.claims.filter((claim) => claim.kind === "command" && !claim.negated).length;
        return { issues: checkCommands(context.claims, context.projectRoot, context.project), checked };
      },
    },
    {
      name: "dependency",
      run(context) {
        const checked = context.claims.filter(
          (claim) => (claim.kind === "dependency" || claim.kind === "version") && !claim.negated
        ).length;
        return { issues: checkDependencies(context.claims, context.projectRoot, context.project), checked };
      },
    },
    {
      name: "cross-file",
      run(context) {
        const checked = context.claims.filter((claim) => claim.kind === "version" && !claim.negated).length;
        return { issues: checkCrossFile(context.claims), checked };
      },
    },
    {
      name: "workspace-dependencies",
      run(context) {
        return {
          issues: checkWorkspaceDependencies(
            context.scaffoldFiles,
            context.project,
            context.projectRoot
          ),
          checked: context.project.workspaceDependencies.length,
        };
      },
    },
    {
      name: "index-sync",
      run(context) {
        return {
          issues: checkIndexSync(context.projectRoot, context.scaffoldRoot),
          checked: 1,
        };
      },
    },
    {
      name: "tool-configs",
      run(context) {
        return {
          issues: checkToolConfigs(context.projectRoot),
          checked: getExistingToolConfigs(context.projectRoot).length,
        };
      },
    },
    {
      name: "script-coverage",
      run(context) {
        return {
          issues: checkScriptCoverage(context.scaffoldFiles, context.projectRoot),
          checked: 1,
        };
      },
    },
  ];
}

export function selectDriftRegistry(
  registry: DriftChecker[],
  opts: { only?: DriftCheckerName[]; skip?: DriftCheckerName[] }
): DriftChecker[] {
  const only = opts.only ? new Set(opts.only) : null;
  const skip = opts.skip ? new Set(opts.skip) : null;

  return registry.filter((checker) => {
    if (only && !only.has(checker.name)) return false;
    if (skip && skip.has(checker.name)) return false;
    return true;
  });
}

export async function runCheckerRegistry(
  context: DriftContext,
  registry = createDriftRegistry()
): Promise<{ issues: DriftIssue[]; summaries: CheckerSummary[] }> {
  const allIssues: DriftIssue[] = [];
  const summaries: CheckerSummary[] = [];

  for (const checker of registry) {
    try {
      const result = await checker.run(context);
      allIssues.push(...result.issues);
      summaries.push({
        name: checker.name,
        checked: result.checked,
        issuesFound: result.issues.length,
      });
    } catch (err) {
      const message = (err as Error).message;
      allIssues.push({
        code: "CHECKER_ERROR",
        severity: "warning",
        file: `[checker:${checker.name}]`,
        line: null,
        message: `Checker '${checker.name}' failed: ${message}`,
      });
      summaries.push({ name: checker.name, checked: 0, issuesFound: 0, error: message });
    }
  }

  return { issues: allIssues, summaries };
}
